                            "language": "xml",
                            "content": "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<!DOCTYPE mapper PUBLIC \"-//mybatis.org//DTD Mapper 3.0//EN\"\n        \"http://mybatis.org/dtd/mybatis-3-mapper.dtd\">\n<mapper namespace=\"com.example.authservice.mapper.AuthUserMapper\">\n\n    <select id=\"findCredentials\" resultType=\"map\">\n        SELECT usr_id   AS \"usrId\",\n               co_cd    AS \"coCd\",\n               usr_nm   AS \"usrNm\",\n               usr_pwd  AS \"usrPwd\",\n               act_flg  AS \"actFlg\",\n               full_nm  AS \"fullNm\"\n        FROM adm_usr\n        WHERE co_cd = #{coCd}\n          AND usr_id = #{usrId}\n          AND (delt_sts_flg != 'Y' OR delt_sts_flg IS NULL)\n    </select>\n</mapper>\n"
