                    "content": "spring:\n  application:\n    name: cache-service\n  data:\n    redis:\n      host: ${SPRING_DATA_REDIS_HOST:localhost}\n      port: ${SPRING_DATA_REDIS_PORT:6379}\n      password: ${SPRING_DATA_REDIS_PASSWORD:}\n  kafka:\n    bootstrap-servers: ${APP_KAFKA_BOOTSTRAP_SERVERS:localhost:9092}\n    consumer:\n      auto-offset-reset: earliest\n      key-deserializer: org.apache.kafka.common.serialization.StringDeserializer\n      value-deserializer: org.apache.kafka.common.serialization.StringDeserializer\n  rabbitmq:\n    host: ${SPRING_RABBITMQ_HOST:localhost}\n    port: ${SPRING_RABBITMQ_PORT:5672}\n    username: ${SPRING_RABBITMQ_USERNAME:guest}\n    password: ${SPRING_RABBITMQ_PASSWORD:guest}\n    listener:\n      simple:\n        missing-queues-fatal: false\n\nserver:\n  port: ${SERVER_PORT:8082}\n\napp:\n  kafka:\n    user-topic: ${APP_KAFKA_USER_TOPIC:user.events}\n    auth-topic: ${APP_KAFKA_AUTH_TOPIC:auth.events}\n  rabbitmq:\n    file-activity-exchange: ${APP_RABBITMQ_FILE_ACTIVITY_EXCHANGE:file.activity.exchange}\n    file-activity-queue: ${APP_RABBITMQ_FILE_ACTIVITY_QUEUE:file.activity.cache.queue}\n    file-activity-routing-key: ${APP_RABBITMQ_FILE_ACTIVITY_ROUTING_KEY:file.activity.cache}\n\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: health,info\n\nspringdoc:\n  api-docs:\n    path: /v3/api-docs\n  swagger-ui:\n    path: /swagger-ui.html\n"
