    "content": "services:\n  postgres:\n    image: postgres:16-alpine\n    container_name: demo-postgres\n    environment:\n      POSTGRES_DB: demoaws\n      POSTGRES_USER: demo\n      POSTGRES_PASSWORD: demo\n    ports:\n      - \"5432:5432\"\n    volumes:\n      - postgres-data:/var/lib/postgresql/data\n      - ./db/init.sql:/docker-entrypoint-initdb.d/init.sql\n    healthcheck:\n      test: [\"CMD-SHELL\", \"pg_isready -U demo -d demoaws\"]\n      interval: 5s\n      timeout: 5s\n      retries: 5\n\n  redis:\n    image: redis:7-alpine\n    container_name: demo-redis\n    ports:\n      - \"6379:6379\"\n    healthcheck:\n      test: [\"CMD\", \"redis-cli\", \"ping\"]\n      interval: 5s\n      timeout: 5s\n      retries: 5\n\n  zookeeper:\n    image: confluentinc/cp-zookeeper:7.6.1\n    container_name: demo-zookeeper\n    environment:\n      ZOOKEEPER_CLIENT_PORT: 2181\n      ZOOKEEPER_TICK_TIME: 2000\n    ports:\n      - \"2181:2181\"\n\n  kafka:\n    image: confluentinc/cp-kafka:7.6.1\n    container_name: demo-kafka\n    depends_on:\n      - zookeeper\n    ports:\n      - \"9092:9092\"\n    environment:\n      KAFKA_BROKER_ID: 1\n      KAFKA_ZOOKEEPER_CONNECT: zookeeper:2181\n      KAFKA_LISTENER_SECURITY_PROTOCOL_MAP: PLAINTEXT:PLAINTEXT,PLAINTEXT_HOST:PLAINTEXT\n      KAFKA_ADVERTISED_LISTENERS: PLAINTEXT://kafka:29092,PLAINTEXT_HOST://localhost:9092\n      KAFKA_INTER_BROKER_LISTENER_NAME: PLAINTEXT\n      KAFKA_OFFSETS_TOPIC_REPLICATION_FACTOR: 1\n      KAFKA_AUTO_CREATE_TOPICS_ENABLE: \"true\"\n    healthcheck:\n      test: [\"CMD-SHELL\", \"kafka-broker-api-versions --bootstrap-server localhost:9092\"]\n      interval: 10s\n      timeout: 10s\n      retries: 5\n\n  rabbitmq:\n    image: rabbitmq:3-management\n    container_name: demo-rabbitmq\n    ports:\n      - \"5672:5672\"\n      - \"15672:15672\"\n    healthcheck:\n      test: [\"CMD\", \"rabbitmq-diagnostics\", \"-q\", \"ping\"]\n      interval: 10s\n      timeout: 10s\n      retries: 5\n\n  auth-service:\n    build:\n      context: .\n      dockerfile: Dockerfile\n      args:\n        MODULE_NAME: auth-service\n    depends_on:\n      postgres:\n        condition: service_healthy\n      kafka:\n        condition: service_healthy\n    environment:\n      SERVER_PORT: 8084\n      SPRING_DATASOURCE_URL: jdbc:postgresql://postgres:5432/demoaws?currentSchema=us_fwd\n      SPRING_DATASOURCE_USERNAME: demo\n      SPRING_DATASOURCE_PASSWORD: demo\n      APP_JWT_SECRET: dGhpcyBpcyBhIHZlcnkgbG9uZyBzZWNyZXQga2V5IGZvciBkZW1vIHB1cnBvc2VzIG9ubHkgLSBjaGFuZ2UgaXQgaW4gcHJvZHVjdGlvbiAtIG1pbiA1MTIgYml0cw==\n      APP_KAFKA_BOOTSTRAP_SERVERS: kafka:29092\n    ports:\n      - \"8084:8084\"\n\n  user-service:\n    build:\n      context: .\n      dockerfile: Dockerfile\n      args:\n        MODULE_NAME: user-service\n    depends_on:\n      postgres:\n        condition: service_healthy\n      kafka:\n        condition: service_healthy\n    environment:\n      SERVER_PORT: 8081\n      SPRING_DATASOURCE_URL: jdbc:postgresql://postgres:5432/demoaws?currentSchema=us_fwd\n      SPRING_DATASOURCE_USERNAME: demo\n      SPRING_DATASOURCE_PASSWORD: demo\n      APP_KAFKA_BOOTSTRAP_SERVERS: kafka:29092\n    ports:\n      - \"8081:8081\"\n\n  cache-service:\n    build:\n      context: .\n      dockerfile: Dockerfile\n      args:\n        MODULE_NAME: cache-service\n    depends_on:\n      redis:\n        condition: service_healthy\n      kafka:\n        condition: service_healthy\n      rabbitmq:\n        condition: service_healthy\n    environment:\n      SERVER_PORT: 8082\n      SPRING_DATA_REDIS_HOST: redis\n      SPRING_DATA_REDIS_PORT: 6379\n      APP_KAFKA_BOOTSTRAP_SERVERS: kafka:29092\n      SPRING_RABBITMQ_HOST: rabbitmq\n      SPRING_RABBITMQ_PORT: 5672\n    ports:\n      - \"8082:8082\"\n\n  file-service:\n    build:\n      context: .\n      dockerfile: Dockerfile\n      args:\n        MODULE_NAME: file-service\n    depends_on:\n      rabbitmq:\n        condition: service_healthy\n    environment:\n      SERVER_PORT: 8083\n      SPRING_RABBITMQ_HOST: rabbitmq\n      SPRING_RABBITMQ_PORT: 5672\n      APP_AWS_REGION: ${APP_AWS_REGION:-us-east-1}\n      APP_AWS_ACCESS_KEY_ID: ${APP_AWS_ACCESS_KEY_ID:-}\n      APP_AWS_SECRET_ACCESS_KEY: ${APP_AWS_SECRET_ACCESS_KEY:-}\n      APP_AWS_ENDPOINT: ${APP_AWS_ENDPOINT:-}\n      APP_STORAGE_BUCKET: ${APP_STORAGE_BUCKET:-demo-bucket}\n    ports:\n      - \"8083:8083\"\n\n  notification-service:\n    build:\n      context: .\n      dockerfile: Dockerfile\n      args:\n        MODULE_NAME: notification-service\n    depends_on:\n      kafka:\n        condition: service_healthy\n      rabbitmq:\n        condition: service_healthy\n    environment:\n      SERVER_PORT: 8085\n      APP_KAFKA_BOOTSTRAP_SERVERS: kafka:29092\n      SPRING_RABBITMQ_HOST: rabbitmq\n      SPRING_RABBITMQ_PORT: 5672\n    ports:\n      - \"8085:8085\"\n\n  api-gateway:\n    build:\n      context: .\n      dockerfile: Dockerfile\n      args:\n        MODULE_NAME: api-gateway\n    depends_on:\n      - auth-service\n      - user-service\n      - cache-service\n      - file-service\n      - notification-service\n      - learning-service\n      - redis\n    environment:\n      SERVER_PORT: 8080\n      SERVICES_AUTH_SERVICE_URL: http://auth-service:8084\n      SERVICES_USER_SERVICE_URL: http://user-service:8081\n      SERVICES_CACHE_SERVICE_URL: http://cache-service:8082\n      SERVICES_FILE_SERVICE_URL: http://file-service:8083\n      SERVICES_NOTIFICATION_SERVICE_URL: http://notification-service:8085\n      SERVICES_LEARNING_SERVICE_URL: http://learning-service:8086\n      APP_JWT_SECRET: dGhpcyBpcyBhIHZlcnkgbG9uZyBzZWNyZXQga2V5IGZvciBkZW1vIHB1cnBvc2VzIG9ubHkgLSBjaGFuZ2UgaXQgaW4gcHJvZHVjdGlvbiAtIG1pbiA1MTIgYml0cw==\n      SPRING_DATA_REDIS_HOST: redis\n      SPRING_DATA_REDIS_PORT: 6379\n    ports:\n      - \"8080:8080\"\n\n  learning-service:\n    build:\n      context: .\n      dockerfile: Dockerfile\n      args:\n        MODULE_NAME: learning-service\n    environment:\n      SERVER_PORT: 8086\n    ports:\n      - \"8086:8086\"\n\n  frontend:\n    build:\n      context: ./frontend\n      dockerfile: Dockerfile\n    depends_on:\n      - api-gateway\n    ports:\n      - \"3000:80\"\n\nvolumes:\n  postgres-data:\n"
