    "content": "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<project xmlns=\"http://maven.apache.org/POM/4.0.0\"\n         xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\"\n         xsi:schemaLocation=\"http://maven.apache.org/POM/4.0.0 https://maven.apache.org/xsd/maven-4.0.0.xsd\">\n    <modelVersion>4.0.0</modelVersion>\n\n    <parent>\n        <groupId>org.springframework.boot</groupId>\n        <artifactId>spring-boot-starter-parent</artifactId>\n        <version>3.2.6</version>\n        <relativePath/>\n    </parent>\n\n    <groupId>com.example</groupId>\n    <artifactId>demo-aws-platform</artifactId>\n    <version>0.0.1-SNAPSHOT</version>\n    <packaging>pom</packaging>\n    <name>demo-aws-platform</name>\n    <description>Microservice platform extracted from the original demo AWS application.</description>\n\n    <modules>\n        <module>user-service</module>\n        <module>auth-service</module>\n        <module>cache-service</module>\n        <module>file-service</module>\n        <module>notification-service</module>\n        <module>api-gateway</module>\n        <module>learning-service</module>\n    </modules>\n\n    <properties>\n        <java.version>17</java.version>\n        <spring-cloud.version>2023.0.1</spring-cloud.version>\n        <aws.sdk.version>2.31.14</aws.sdk.version>\n    </properties>\n\n    <dependencyManagement>\n        <dependencies>\n            <dependency>\n                <groupId>org.springframework.cloud</groupId>\n                <artifactId>spring-cloud-dependencies</artifactId>\n                <version>${spring-cloud.version}</version>\n                <type>pom</type>\n                <scope>import</scope>\n            </dependency>\n            <dependency>\n                <groupId>software.amazon.awssdk</groupId>\n                <artifactId>bom</artifactId>\n                <version>${aws.sdk.version}</version>\n                <type>pom</type>\n                <scope>import</scope>\n            </dependency>\n        </dependencies>\n    </dependencyManagement>\n</project>\n"
